(28,223,1,'2026-06-22','GSR','عمر ح','Alt. GSR','مريم',9,'يوجد ترشيحات نائب امين صندوق','2026-07-12 21:15:00',1,'تم التوصيه لاختيار مواضيع الاجتماع بعنايه و عدم تكرار نفس الموضوع لاجتماعين متتاليين','تم ترشح عمر ممثل للمجموعه و تم الموافقه \r\nتم ترشح عبد الرحمن امين للصندوق و تم الموافقه \r\nتم ترشح زيد سكرتير لاجتماع التعافي يوم الاحد و تم الموافقه','تم تقديم تقرير مفصل من امين الصندوق و تم دفع الايجار و يوجد احطياطي حذر ١٠٥ جنيه','[{\"title\":\"\\u062a\\u063a\\u064a\\u0631 \\u0645\\u064a\\u0639\\u0627\\u062f \\u0627\\u0644\\u0627\\u062c\\u062a\\u0645\\u0627\\u0639 \\u0645\\u0639 \\u0627\\u0644\\u063a\\u0627\\u0621 \\u064a\\u0648\\u0645 \\u0627\\u0644\\u062c\\u0645\\u0639\\u0647\",\"content\":\"<p>\\u062a\\u0645 \\u062a\\u0642\\u062f\\u064a\\u0645 \\u0645\\u0642\\u062a\\u0631\\u062d \\u0644\\u0627\\u0644\\u063a\\u0627\\u0621 \\u064a\\u0648\\u0645 \\u0627\\u0644\\u062c\\u0645\\u0639\\u0647 \\u0644\\u064a\\u0635\\u0628\\u062d \\u0627\\u062c\\u062a\\u0645\\u0627\\u0639 \\u0627\\u0644\\u062a\\u0639\\u0627\\u0641\\u064a \\u064a\\u0648\\u0645 \\u0627\\u0644\\u0627\\u062d\\u062f \\u0641\\u0642\\u0637 \\u0648 \\u062a\\u0645 \\u0627\\u0644\\u062a\\u0632\\u0643\\u064a\\u0647 \\u0648 \\u0641\\u062a\\u062d \\u0627\\u0644\\u0645\\u0648\\u0636\\u0648\\u0639 \\u0644\\u0644\\u0645\\u0646\\u0627\\u0642\\u0634\\u0647 \\u0648 \\u0627\\u0644\\u0645\\u0648\\u0627\\u0641\\u0642\\u0647 \\u0639\\u0644\\u064a \\u0627\\u0644\\u0645\\u0642\\u062a\\u0631\\u062d <\\/p>\"}]','2026-06-22 16:29:45','2026-06-22 16:29:45'),
(29,210,3,'2026-06-25','GSR','طارق','Alt. GSR','AHMED',5,'ترشيحت سكرتير اوليوم الاحد \r\nسكرتير تانى يوم الجمعه','2026-06-25 21:00:00',0,'تغيير ميعاد اجتماع عمل القادم مؤقتا لحين اتخاذ قرار بنقل مقر مجموعه وتغييره على الموقع \r\nتم الاتفاق على وضع اليه وبعض قيود على مواقع التواصل الخاصه بخدم مجموعه لترتيب مواضيع ووضع الاولويه للاستفاده من اجتماع عمل مجموعه','شكر خاص من خد مجموعه للجنة الدعم والادبيات الفرعيه للمنتدى لدعمهم الوافى من مساعده وتوفير معلمومات اثناء ورشالعمل الخاصه بالمجموعه واهتمامهم بحضور اجتماع عمل مجموعه \r\nتم الاتفاق على تنويه التقرير المالى اثناء اجتماع تعافى طبقا للتقرير المالى من امين صندوق','5280 من 15-5 الى 19-06 \r\n515ادبيات \r\n4500 ايجار \r\n265 تبرع','[{\"title\":\"\\u0637\\u0644\\u0628 \\u0645\\u0633\\u0627\\u0639\\u062f\\u0647 \\u0644\\u0644\\u062a\\u0648\\u0636\\u064a\\u062d\",\"content\":\"<p>\\u0645\\u0648\\u0636\\u0648\\u0639 \\u062c\\u062f\\u0627\\u0648\\u0644 \\u0645\\u0637\\u0628\\u0648\\u0639\\u0647 \\u0627\\u0644\\u062e\\u0627\\u0635\\u0647 \\u0628\\u0627\\u0644\\u0645\\u0646\\u062a\\u062f\\u0649<\\/p>\"}]','2026-06-25 15:00:26','2026-06-25 15:00:26'),
