(1688,'Meeting','update','{\"notes\":\"\\u0644\\u0634\\u0631\\u0648\\u0637 \\u0627\\u0644\\u0645\\u0631\\u0641\\u0642 \\u0627\\u0644\\u0645\\u062a\\u0648\\u0627\\u0641\\u0642 \\u0639\\u0644\\u064a\\u0647\\u0627 \\u0645\\u0646 \\u0627\\u0644\\u0645\\u062c\\u0645\\u0648\\u0639\\u0647 \\u0645\\u0645\\u0646\\u0648\\u0639 \\u0627\\u0644\\u062f\\u062e\\u0648\\u0644 \\u0628\\u0625\\u062b\\u0628\\u0627\\u062a \\u0634\\u062e\\u0635\\u064a\\u0647 ( \\u0627\\u0644\\u0628\\u0637\\u0627\\u0642\\u0647 \\u0634\\u062e\\u0635\\u064a\\u0647 \\u0627\\u0648 \\u0634\\u0647\\u0627\\u062f\\u0647 \\u0645\\u064a\\u0644\\u0627\\u062f \\u0627\\u0648 \\u062c\\u0648\\u0627\\u0632 \\u0633\\u0641\\u0631 ) \\u0648\\u0627\\u064a\\u0636\\u0627\\u064b \\u0645\\u0645\\u0646\\u0648\\u0639 \\u0627\\u0644\\u062f\\u062e\\u0648\\u0644 \\u0628\\u0634\\u0648\\u0631\\u062a\\r\\n\\u0648\\u0647\\u0630\\u0627 \\u0644\\u0623\\u0646 \\u0627\\u0644\\u0645\\u0646\\u0634\\u0623\\u0629 \\u062a\\u0627\\u0628\\u0639\\u0647 \\u0644\\u0644\\u0642\\u0648\\u0627\\u062a \\u0627\\u0644\\u0645\\u0633\\u0644\\u062d\\u0647\"}','{\"notes\":\"\\u0644\\u0634\\u0631\\u0648\\u0637 \\u0627\\u0644\\u0645\\u0631\\u0641\\u0642 \\u0627\\u0644\\u0645\\u062a\\u0648\\u0627\\u0641\\u0642 \\u0639\\u0644\\u064a\\u0647\\u0627 \\u0645\\u0646 \\u0627\\u0644\\u0645\\u062c\\u0645\\u0648\\u0639\\u0647 \\u0645\\u0645\\u0646\\u0648\\u0639 \\u0627\\u0644\\u062f\\u062e\\u0648\\u0644 \\u0625\\u0644\\u0627 \\u0628\\u0625\\u062b\\u0628\\u0627\\u062a \\u0634\\u062e\\u0635\\u064a\\u0647 ( \\u0627\\u0644\\u0628\\u0637\\u0627\\u0642\\u0647 \\u0634\\u062e\\u0635\\u064a\\u0647 \\u0627\\u0648 \\u0634\\u0647\\u0627\\u062f\\u0647 \\u0645\\u064a\\u0644\\u0627\\u062f \\u0627\\u0648 \\u062c\\u0648\\u0627\\u0632 \\u0633\\u0641\\u0631 ) \\u0648\\u0627\\u064a\\u0636\\u0627\\u064b \\u0645\\u0645\\u0646\\u0648\\u0639 \\u0627\\u0644\\u062f\\u062e\\u0648\\u0644 \\u0628\\u0634\\u0648\\u0631\\u062a\"}','{\"notes\":\"\\u0644\\u0634\\u0631\\u0648\\u0637 \\u0627\\u0644\\u0645\\u06